+#[test]
+fn open_tree_null_path_sets_efault_like_host() {
+    unsafe {
+        *__errno_location() = 0;
+    }
+    let rc = unsafe { open_tree(libc::AT_FDCWD, ptr::null(), 0) };
+    let err = unsafe { *__errno_location() };
+
+    assert_eq!(rc, -1);
+    assert_eq!(
+        err,
+        libc::EFAULT,
+        "unexpected errno from open_tree(null): {err}"
+    );
+}
